/**
 * 迭代事件发射器 - 连接 AutoIterationEngine 和 Dashboard
 */
import { EventEmitter } from 'events';

export class IterationEventEmitter extends EventEmitter {
  private static instance: IterationEventEmitter;

  static getInstance(): IterationEventEmitter {
    if (!this.instance) {
      this.instance = new IterationEventEmitter();
    }
    return this.instance;
  }

  // 迭代生命周期事件
  emitIterationStart(data: { iterationNumber: number; timestamp: Date }) {
    this.emit('iteration.start', data);
  }

  emitIterationComplete(data: { iterationNumber: number; status: string }) {
    this.emit('iteration.complete', data);
  }

  // Agent 事件
  emitAgentStart(data: { agentName: string; task: string }) {
    this.emit('agent.start', data);
  }

  emitAgentProgress(data: { agentName: string; progress: number }) {
    this.emit('agent.progress', data);
  }

  emitAgentComplete(data: { agentName: string; result: string }) {
    this.emit('agent.complete', data);
  }
}
```

